// S3 configuration with defaults pointing to local MinIO
func s3Config() (endpoint, bucket, region, accessKey, secretKey string) {
	endpoint = getEnv("S3_ENDPOINT", "http://127.0.0.1:9000")
	bucket = getEnv("S3_BUCKET", "uploads")
	region = getEnv("S3_REGION", "us-east-1")
	accessKey = getEnv("S3_ACCESS_KEY", "minioadmin")
	secretKey = getEnv("S3_SECRET_KEY", "minioadmin")
	return
}

func getEnv(key, defaultVal string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return defaultVal
}

func newS3Client() (*s3.Client, string, error) {
	endpoint, bucket, region, accessKey, secretKey := s3Config()

	customResolver := aws.EndpointResolverWithOptionsFunc(
		func(service, reg string, options ...interface{}) (aws.Endpoint, error) {
			return aws.Endpoint{
				URL:               endpoint,
				SigningRegion:      region,
				HostnameImmutable: true,
			}, nil
		},
	)

	cfg, err := awsconfig.LoadDefaultConfig(context.Background(),
		awsconfig.WithRegion(region),
		awsconfig.WithEndpointResolverWithOptions(customResolver),
		awsconfig.WithCredentialsProvider(
			credentials.NewStaticCredentialsProvider(accessKey, secretKey, ""),
		),
	)
	if err != nil {
		return nil, bucket, fmt.Errorf("failed to load AWS config: %w", err)
	}

	client := s3.NewFromConfig(cfg, func(o *s3.Options) {
		o.UsePathStyle = true
	})
	return client, bucket, nil
}

func newPresignClient() (*s3.PresignClient, string, error) {
	client, bucket, err := newS3Client()
	if err != nil {
		return nil, bucket, err
	}
	return s3.NewPresignClient(client), bucket, nil
}

// bootstrapCollections ensures the required collections exist.
func bootstrapCollections(app core.App) error {
	// --- pending_upload collection ---
	pendingColl, err := app.FindCollectionByNameOrId("pending_upload")
	if err != nil {
		// Create it
		pendingColl = core.NewBaseCollection("pending_upload")

		usersColl, err := app.FindCollectionByNameOrId("users")
		if err != nil {
			return fmt.Errorf("cannot find users collection: %w", err)
		}

		userField := core.NewRelationField("user")
		userField.Required = true
		userField.CollectionId = usersColl.Id
		userField.MaxSelect = 1
		pendingColl.Fields.Add(userField)

		keyField := core.NewTextField("key")
		keyField.Required = true
		pendingColl.Fields.Add(keyField)

		expiresAtField := core.NewDateField("expires_at")
		expiresAtField.Required = true
		pendingColl.Fields.Add(expiresAtField)

		// Add unique index on key
		pendingColl.AddIndex("idx_pending_upload_key", true, "key", "")

		if err := app.Save(pendingColl); err != nil {
			return fmt.Errorf("failed to create pending_upload collection: %w", err)
		}
		log.Println("Created pending_upload collection")
	} else {
		log.Println("pending_upload collection already exists:", pendingColl.Id)
	}

	// --- uploads collection ---
	_, err = app.FindCollectionByNameOrId("uploads")
	if err != nil {
		uploadsColl := core.NewBaseCollection("uploads")

		usersColl, err := app.FindCollectionByNameOrId("users")
		if err != nil {
			return fmt.Errorf("cannot find users collection: %w", err)
		}

		userField := core.NewRelationField("user")
		userField.Required = true
		userField.CollectionId = usersColl.Id
		userField.MaxSelect = 1
		uploadsColl.Fields.Add(userField)

		keyField := core.NewTextField("key")
		keyField.Required = true
		uploadsColl.Fields.Add(keyField)

		// Add unique index on key
		uploadsColl.AddIndex("idx_uploads_key", true, "key", "")

		if err := app.Save(uploadsColl); err != nil {
			return fmt.Errorf("failed to create uploads collection: %w", err)
		}
		log.Println("Created uploads collection")
	} else {
		log.Println("uploads collection already exists")
	}

	return nil
}

// seedUsers ensures the required users exist.
func seedUsers(app core.App) error {
	usersColl, err := app.FindCollectionByNameOrId("users")
	if err != nil {
		return fmt.Errorf("cannot find users collection: %w", err)
	}

	type seedUser struct {
		email    string
		password string
	}
	users := []seedUser{
		{"user@example.com", "password1234"},
		{"other@example.com", "password1234"},
	}

	for _, u := range users {
		existing, err := app.FindAuthRecordByEmail(usersColl.Id, u.email)
		if err == nil && existing != nil {
			log.Printf("User %s already exists", u.email)
			continue
		}

		record := core.NewRecord(usersColl)
		record.Set("email", u.email)
		record.Set("emailVisibility", true)
		if err := record.SetPassword(u.password); err != nil {
			return fmt.Errorf("failed to set password for %s: %w", u.email, err)
		}
		record.Set("verified", true)
		if err := app.Save(record); err != nil {
			return fmt.Errorf("failed to save user %s: %w", u.email, err)
		}
		log.Printf("Created user %s", u.email)
	}
	return nil
}

// seedSuperuser ensures the superuser exists.
func seedSuperuser(app core.App) error {
	email := "admin@example.com"
	password := "1234567890"

	existing, err := app.FindAuthRecordByEmail(core.CollectionNameSuperusers, email)
	if err == nil && existing != nil {
		log.Printf("Superuser %s already exists", email)
		return nil
	}

	superusersColl, err := app.FindCollectionByNameOrId(core.CollectionNameSuperusers)
	if err != nil {
		return fmt.Errorf("cannot find superusers collection: %w", err)
	}

	record := core.NewRecord(superusersColl)
	record.Set("email", email)
	if err := record.SetPassword(password); err != nil {
		return fmt.Errorf("failed to set superuser password: %w", err)
	}
	if err := app.Save(record); err != nil {
		return fmt.Errorf("failed to save superuser: %w", err)
	}
	log.Printf("Created superuser %s", email)
	return nil
}

func main() {
	app := pocketbase.New()

	// Bootstrap collections and seed data on app start (before serving)
	app.OnServe().BindFunc(func(se *core.ServeEvent) error {
		if err := bootstrapCollections(se.App); err != nil {
			return fmt.Errorf("bootstrapCollections: %w", err)
		}
		if err := seedSuperuser(se.App); err != nil {
			return fmt.Errorf("seedSuperuser: %w", err)
		}
		if err := seedUsers(se.App); err != nil {
			return fmt.Errorf("seedUsers: %w", err)
		}

		// Register custom routes
		se.Router.POST("/api/uploads/presign", handlePresign(se.App))
		se.Router.POST("/api/uploads/finalize", handleFinalize(se.App))

		return se.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

// requireUser extracts and validates the Bearer token from the request,
// returning the authenticated user record, or writing an error response.
func requireUser(app core.App, r *http.Request, w http.ResponseWriter) *core.Record {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		writeJSON(w, http.StatusUnauthorized, map[string]string{"error": "missing authorization header"})
		return nil
	}

	// Strip "Bearer " prefix if present
	token := authHeader
	if len(authHeader) > 7 && authHeader[:7] == "Bearer " {
		token = authHeader[7:]
	}

	record, err := app.FindAuthRecordByToken(token, core.TokenTypeAuth)
	if err != nil || record == nil {
		writeJSON(w, http.StatusUnauthorized, map[string]string{"error": "invalid or expired token"})
		return nil
	}

	// Ensure it's a user (not a superuser)
	if record.Collection().Name != "users" {
		writeJSON(w, http.StatusUnauthorized, map[string]string{"error": "only users can access this endpoint"})
		return nil
	}

	return record
}

func writeJSON(w http.ResponseWriter, status int, v any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	_ = json.NewEncoder(w).Encode(v)
}

// handlePresign generates a presigned S3 PUT URL and records it in pending_upload.
func handlePresign(app core.App) func(e *core.RequestEvent) error {
	return func(e *core.RequestEvent) error {
		user := requireUser(app, e.Request, e.Response)
		if user == nil {
			return nil
		}

		// Generate a UUID key for the object
		key := uuid.New().String()

		presignClient, bucket, err := newPresignClient()
		if err != nil {
			writeJSON(e.Response, http.StatusInternalServerError, map[string]string{"error": "s3 client error: " + err.Error()})
			return nil
		}

		presignDuration := 300 * time.Second

		req, err := presignClient.PresignPutObject(context.Background(), &s3.PutObjectInput{
			Bucket: aws.String(bucket),
			Key:    aws.String(key),
		}, s3.WithPresignExpires(presignDuration))
		if err != nil {
			writeJSON(e.Response, http.StatusInternalServerError, map[string]string{"error": "presign error: " + err.Error()})
			return nil
		}

		expiresAt := time.Now().UTC().Add(presignDuration)
		expiresAtStr := expiresAt.Format(time.RFC3339)

		// Validate the presigned URL contains path-style addressing
		parsedURL, parseErr := url.Parse(req.URL)
		if parseErr != nil {
			log.Printf("Warning: could not parse presigned URL: %v", parseErr)
		} else {
			log.Printf("Presigned URL host: %s, path: %s", parsedURL.Host, parsedURL.Path)
		}

		// Save pending_upload record
		pendingColl, err := app.FindCollectionByNameOrId("pending_upload")
		if err != nil {
			writeJSON(e.Response, http.StatusInternalServerError, map[string]string{"error": "cannot find pending_upload collection"})
			return nil
		}

		record := core.NewRecord(pendingColl)
		record.Set("user", user.Id)
		record.Set("key", key)

		t, _ := types.ParseDateTime(expiresAt)
		record.Set("expires_at", t)

		if err := app.Save(record); err != nil {
			writeJSON(e.Response, http.StatusInternalServerError, map[string]string{"error": "failed to save pending_upload: " + err.Error()})
			return nil
		}

		writeJSON(e.Response, http.StatusOK, map[string]string{
			"url":       req.URL,
			"key":       key,
			"expiresAt": expiresAtStr,
		})
		return nil
	}
}

// handleFinalize verifies the object exists in S3, cleans up pending_upload, and creates an uploads record.
func handleFinalize(app core.App) func(e *core.RequestEvent) error {
	return func(e *core.RequestEvent) error {
		user := requireUser(app, e.Request, e.Response)
		if user == nil {
			return nil
		}

		var body struct {
			Key string `json:"key"`
		}
		if err := json.NewDecoder(e.Request.Body).Decode(&body); err != nil || body.Key == "" {
			writeJSON(e.Response, http.StatusBadRequest, map[string]string{"error": "invalid request body, 'key' required"})
			return nil
		}

		// Look up pending_upload record
		pendingColl, err := app.FindCollectionByNameOrId("pending_upload")
		if err != nil {
			writeJSON(e.Response, http.StatusInternalServerError, map[string]string{"error": "cannot find pending_upload collection"})
			return nil
		}

		records, err := app.FindRecordsByFilter(
			pendingColl.Id,
			"key = {:key}",
			"", 1, 0,
			dbx.Params{"key": body.Key},
		)
		if err != nil || len(records) == 0 {
			writeJSON(e.Response, http.StatusNotFound, map[string]string{"error": "pending upload not found"})
			return nil
		}

		pendingRecord := records[0]

		// Check ownership
		if pendingRecord.GetString("user") != user.Id {
			writeJSON(e.Response, http.StatusNotFound, map[string]string{"error": "pending upload not found"})
			return nil
		}

		// Verify object exists in S3
		s3Client, bucket, err := newS3Client()
		if err != nil {
			writeJSON(e.Response, http.StatusInternalServerError, map[string]string{"error": "s3 client error: " + err.Error()})
			return nil
		}

		_, headErr := s3Client.HeadObject(context.Background(), &s3.HeadObjectInput{
			Bucket: aws.String(bucket),
			Key:    aws.String(body.Key),
		})
		if headErr != nil {
			writeJSON(e.Response, http.StatusNotFound, map[string]string{"error": "object not found in S3"})
			return nil
		}

		// Delete pending_upload record
		if err := app.Delete(pendingRecord); err != nil {
			writeJSON(e.Response, http.StatusInternalServerError, map[string]string{"error": "failed to delete pending_upload: " + err.Error()})
			return nil
		}

		// Create uploads record
		uploadsColl, err := app.FindCollectionByNameOrId("uploads")
		if err != nil {
			writeJSON(e.Response, http.StatusInternalServerError, map[string]string{"error": "cannot find uploads collection"})
			return nil
		}

		uploadRecord := core.NewRecord(uploadsColl)
		uploadRecord.Set("user", user.Id)
		uploadRecord.Set("key", body.Key)

		if err := app.Save(uploadRecord); err != nil {
			writeJSON(e.Response, http.StatusInternalServerError, map[string]string{"error": "failed to save upload record: " + err.Error()})
			return nil
		}

		writeJSON(e.Response, http.StatusOK, map[string]string{
			"key": body.Key,
		})
		return nil
	}
}

